import { Badge } from "@/components/ui/badge";
import type { ApplicantStatus } from "@/lib/types";

const statusVariant: Record<ApplicantStatus, "muted" | "amber" | "teal" | "red"> = {
  Applied: "muted",
  Screening: "amber",
  Interview: "amber",
  Offered: "teal",
  Hired: "teal",
  Rejected: "red"
};

export function ApplicantStatusBadge({ status }: { status: ApplicantStatus }) {
  return <Badge variant={statusVariant[status]}>{status}</Badge>;
}
